module top_module(
	input wire clk,
    input wire ce,
	input wire [9:0] a,
	input wire [7:0] din,
	output reg [7:0] dout,
	input wire we
	);reg [7:0] ram[0:1023];
    always @(posedge clk) begin
        dout <= ram[a];
        if (we == 1'b1 && ce == 1'b1)
            ram[a] <= din;
    end
endmodule
